VALUES
  ('locality-e0adf6cd-moex-00080', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '國立大學為確保學生具有一定之專業能力，授權各系所訂定考試規則，以明定系所學生取得學分 之條件，下列何者為考試規則之合憲性依據？', '["平等原則", "大學自治", "住民自治", "誠信原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00081', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '有關行政處分無效事由之敘述，下列何者錯誤？', '["未經授權而違背法規有關管轄之規定，主要係指欠缺事物管轄及土地管轄之情形", "所要求或許可之行為構成犯罪者，係指該行為客觀上違反刑罰之法規，而具有違法性", "應以證書方式作成而未給予證書者，係指凡行政處分應依法定方式作成而有所欠缺者", "不能得知處分機關，係指經由形式觀察，無法得知處分機關之情形"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00082', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '行政機關為達成行政目的，得於行政處分作成時附加附款，下列何者非屬此種附款？', '["經濟部核准甲設定礦業權之申請，惟於同意登記設立礦業權通知函中，註明「如出現重大環境 保護之必要或者發生其他重大土地開發事由，得註銷本設定登記」", "A直轄市政府核准乙設立工廠之申請，並於核准函中附加「每年應提供至少新臺幣50萬元回 饋金」條款", "B縣警察局核准丙示威遊行之申請，惟要求遊行路線須避開活動最後主場之火車站站前廣場", "國家通訊傳播委員會核准丁換發營運執照之申請，核發自發照日起5年為限之營運執照"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00083', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '主管機關 A 認定甲所有之房屋為程序違建，乃對甲寄發違章建築補辦手續通知單（下稱補辦通 知單），限期檢齊文件補辦建造執照，如逾期未補辦將進行拆除。甲逾期未補辦，A機關乃寄發 違章建築拆除通知單（下稱拆除通知單），通知甲限期拆除該房屋。如甲未依期限拆除，A機關 決定代行拆除，再向甲徵收費用，前述2件通知單何者可作為執行名義？', '["僅補辦通知單可作為執行名義", "僅拆除通知單可作為執行名義", "2件通知單均具下命性質而屬行政處分，均可為執行名義", "A機關依法須另為催告，2件通知單均不得作為執行名義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00084', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '甲公立學校錄取公費生乙，甲與乙書面約定，乙若違約，甲得逕依約強制執行。乙就讀一學期後 遭受退學，預估應賠償甲新臺幣5萬元，下列敘述何者錯誤？', '["甲與乙之書面約定性質為行政契約", "如生契約爭議，甲應向高等行政法院地方行政訴訟庭起訴", "甲得依約自行逕行行政強制執行", "甲起訴時應繳納裁判費新臺幣2千元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00085', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於行政指導，下列敘述何者正確？', '["行政指導應符合授權明確性原則", "行政指導屬於行政契約之一種類型", "行政指導之拒絕，相對人須以書面為之", "行政指導仍有法律優位原則之適用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00086', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於行政罰之敘述，下列何者錯誤？', '["一行為違反數個行政法上義務規定且均應處罰鍰時，其罰鍰之金額應依法定罰鍰額最高之規定 裁處，但不得低於各該規定之罰鍰最低額", "違反行政法上義務之處罰，以行為時之法律或自治條例有明文規定者為限", "公立醫院違反廢棄物清理法之行政法上義務，因其屬於公權力主體，主管機關不得裁罰之", "被主管機關接管中之保險公司，仍得作為裁罰之對象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00087', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '某市政府發現民眾甲屋庭院內之樹木，即將傾倒危及民眾，乃直接僱工進入甲屋庭院，鋸倒該樹 木，此行為之法律性質為何？', '["間接強制中之代履行", "行政義務之直接強制", "即時強制", "定暫時狀態之處分 30840、31140 31640、31740 31940"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00088', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '甲向建管機關A申請核發建築執照，但因資料不全經A通知補件；為補齊申請資料，甲遂依行 政程序法向A申請閱覽卷宗，但遭A拒絕，嗣A駁回甲之建照申請。關於甲救濟之敘述，下列 何者正確？', '["得分別針對拒絕閱覽卷宗與駁回建照之決定提起救濟", "僅能針對駁回建照之決定請求救濟，行政機關拒絕閱覽卷宗之決定無法救濟", "對於駁回建照之決定請求救濟之同時，一併對拒絕閱覽卷宗之決定表示不服", "對於拒絕閱覽卷宗與駁回建照之決定皆無法提起救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00089', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於訴願機關審查範圍之敘述，下列何者正確？', '["訴願機關原則上僅得審查行政處分之合法性", "訴願機關審查大學對大學生所為與講學有關之行政處分，應適度尊重大學之專業判斷", "訴願機關得就地方自治團體辦理自治事項所為行政處分之合目的性進行審查", "訴願機關得以自己之判斷取代考試評分事件中原處分機關之判斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL)
